    problem_type: ScannerProblemType,
    absolute_path: &Path,
    relative_path: &Path,
    attribution: Option<&ModIndexedPath>,
    summary: impl Into<String>,
    solution_kind: ScannerSolutionKind,
) -> ScannerResult {
    path_result(
        problem_type,
        absolute_path,
        relative_path,
        attribution,
        summary,
        None,
    )
    .with_solution_kind(solution_kind)
}

